//-------------------------------------------------------------------------
// 회계처리취소
//-------------------------------------------------------------------------
scwin.f_CancleSlip = async function () {
  //       console.log('scwin.f_CancleSlip~~');

  var k = 0;
  for (var i = 0; i < ds_slipList.getRowCount(); i++) {
    //console.log('choice ==> '+ds_slipList.getCellData(i, "choice"));
    if (ds_slipList.getCellData(i, "choice") == "T") {
      if (ds_slipList.getCellData(i, "slipKndCd") != 'F01' && ds_slipList.getCellData(i, "slipKndCd") != 'F02' && ds_slipList.getCellData(i, "slipKndCd") != 'F08') {
        await $c.gus.cfAlertMsg($p, "전표종류가 매출,매입,대납금전표인 것만 취소할 수 있습니다.");
        gr_slipList.setFocusedCell(i, "choice", false);
        //ds_slipList.RowPosition = i;
        //gr_slipList.focus();
        //gr_slipList.SetColumn("choice");							
        return;
      }
      if (ds_slipList.getCellData(i, "dcsnClsCd") != '4') {
        await $c.gus.cfAlertMsg($p, "확정구분이 전표확정인 것만 취소할 수 있습니다.");
        //ds_slipList.RowPosition = i;
        //gr_slipList.focus();
        //gr_slipList.SetColumn("choice");							
        gr_slipList.setFocusedCell(i, "choice", false);
        return;
      }
      if (ds_slipList.getCellData(i, "postDt").substring(0, 6) <= ica_slipCloseYm.getValue()) {
        var msg = "마감완료된 전표 이므로  역전표 생성 됩니다. 마감기간일 경우 마감이 완전히 끝났는지 확인하시고, 작업하십시요!";
        if (!(await $c.win.confirm($p, msg))) {
          //ds_slipList.RowPosition = i;
          //gr_slipList.focus();
          //gr_slipList.SetColumn("choice");	
          gr_slipList.setFocusedCell(i, "choice", false);
          return;
        }
      }
      if (!(await scwin.f_CheckTaxCancelSpplyDt(ds_slipList.getCellData(i, "spplyDt")))) return;
      ds_slipList.setCellData(i, "cancelSpplyDt", ica_cancelSpplyDt.getValue());
      k++;
    }
  }
  if (k < 1) {
    await $c.gus.cfAlertMsg($p, "취소하려는 전표가 선택되지 않았습니다.");
    return;
  }
  $c.sbm.execute($p, sbm_cancelSlip_save);

  //ds_slipList.UseChangeInfo = "false";		
  //tr_cancelSlip_save.Action = "/ja.ds.fs.adjmbilgcomn.JaCancelSlipDecisionCMD.do";
  //tr_cancelSlip_save.Post();
};

//-------------------------------------------------------------------------
// 세금계산서 취소 때  세무마감여부 CHECK
//-------------------------------------------------------------------------
scwin.f_CheckTaxCancelSpplyDt = async function (spplyDt) {
  var taxCloseYm = ica_taxCloseYm.getValue();
  var spplyYm = spplyDt.substring(0, 6);
  var isTrue;
  if (taxCloseYm >= spplyYm) {
    isTrue = await $c.win.confirm($p, "세무마감된 계산서를 취소할 경우에는 반드시 거래처에 수정세금계산서를 발행해야 합니다.(거래처와 합의 요함)\n\n세금계산서 및 전표를 취소하시겠습니까?");
    if (!isTrue) return;
    if ($c.gus.cfIsNull($p, ica_cancelSpplyDt.getValue())) {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["[수정세금계산서 공급일자 ]"]); //@은(는) 필수 입력 항목입니다
      ica_cancelSpplyDt.focus();
      return false;
    }
    if (!(await $c.gus.cfValidate($p, [ica_cancelSpplyDt]))) {
      ica_cancelSpplyDt.focus();
      return false;
    }
  }
  return true;
};

