scwin.f_downExcelSheet = async function () {
  var cfrm = await $c.win.confirm($p, "EXCEL로 다운로드 받으시겠습니까?");
  if (cfrm) {
    const sheetTitle = "전표 확정 조회 및 취소";
    const options = {
      fileName: sheetTitle + ".xlsx" //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
      ,
      sheetName: sheetTitle //엑셀내 시트명 지정필요시
    };
    const infoArr = [];
    $c.data.downloadGridViewExcel($p, gr_slipList, options, infoArr);
  }
};
scwin.sbm_slipList_retrieve_submitdone = async function (e) {
  //debugger;

  try {
    if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
    var rowcnt = ds_slipList.getRowCount();
    tbx_totalRows.setValue(rowcnt);
    if (rowcnt == 0) {
      await $c.gus.cfAlertMsg($p, MSG_CM_WRN_002);
      return;
    }
    ica_slipCloseYm.setValue(ds_slipList.getCellData(0, "slipCloseYm")); //회계마감월
    ica_taxCloseYm.setValue(ds_slipList.getCellData(0, "taxCloseYm")); //세무마감월
  } catch (e) {
    console.log("sbm_retrieve_submitdone : " + e);
  }
};
